import{_ as a,o as t,c as l,a0 as o}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Delete & Restore Kingdoms/Alliances","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/delete-restore-kingdom-alliance.md","filePath":"how-to/delete-restore-kingdom-alliance.md"}'),r={name:"how-to/delete-restore-kingdom-alliance.md"};function i(n,e,s,d,c,h){return t(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="delete-restore-kingdoms-alliances" tabindex="-1">Delete &amp; Restore Kingdoms/Alliances <a class="header-anchor" href="#delete-restore-kingdoms-alliances" aria-label="Permalink to &quot;Delete &amp; Restore Kingdoms/Alliances&quot;">​</a></h1><p>Deleting a kingdom or alliance does not immediately erase it forever. It moves into the recycle-bin flow, where it stays out of normal views and analytics until it is restored or later purged.</p><blockquote><p>Screenshot placeholder: bin-restore-import.png</p></blockquote><h2 id="before-you-delete" tabindex="-1">Before you delete <a class="header-anchor" href="#before-you-delete" aria-label="Permalink to &quot;Before you delete&quot;">​</a></h2><ul><li>Make sure you really want to hide the whole kingdom or alliance from normal use.</li><li>If you only need to fix users or players, use those smaller tools instead.</li><li>Check the recycle-bin rules first so you know who can restore it afterward.</li></ul><p>For the general idea behind deletion in this app, read <a href="./../reference/soft-delete.html">What &quot;Delete&quot; Really Does</a>.</p><h2 id="delete-a-kingdom" tabindex="-1">Delete a kingdom <a class="header-anchor" href="#delete-a-kingdom" aria-label="Permalink to &quot;Delete a kingdom&quot;">​</a></h2><ol><li>Open the kingdom page.</li><li>Use the delete action in the page header.</li><li>Confirm the delete.</li></ol><h2 id="delete-an-alliance" tabindex="-1">Delete an alliance <a class="header-anchor" href="#delete-an-alliance" aria-label="Permalink to &quot;Delete an alliance&quot;">​</a></h2><p>You can delete an alliance from:</p><ul><li>the alliance row on the kingdom page</li><li>the alliance detail page</li></ul><p>After confirmation, it moves out of normal views and into the recycle bin.</p><p>Some alliance deletions can be blocked by ownership or subscription protections. If that happens, resolve the blocking condition first and try again.</p><h2 id="restore-from-the-recycle-bin" tabindex="-1">Restore from the recycle bin <a class="header-anchor" href="#restore-from-the-recycle-bin" aria-label="Permalink to &quot;Restore from the recycle bin&quot;">​</a></h2><ol><li>Open <strong>Recycle Bin</strong>.</li><li>Go to the <strong>Kingdoms</strong> or <strong>Alliances</strong> section.</li><li>Find the deleted item.</li><li>Select <strong>Restore</strong> if you have restore permission.</li></ol><p>If you do not have restore permission but can file reports, use <strong>Request restore</strong> instead.</p><h2 id="what-restore-gives-back" tabindex="-1">What restore gives back <a class="header-anchor" href="#what-restore-gives-back" aria-label="Permalink to &quot;What restore gives back&quot;">​</a></h2><p>Restore brings the kingdom or alliance back into normal views. It does not replace the need to check:</p><ul><li>responsible users</li><li>current players</li><li>recent imports or reports</li><li>any subscription or usage warnings</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./recycle-bin.html">Use the Recycle Bin</a></li><li><a href="./../reference/soft-delete.html">What &quot;Delete&quot; Really Does</a></li><li><a href="./manage-kingdoms.html">Create &amp; Manage Kingdoms</a></li><li><a href="./manage-alliances.html">Create &amp; Manage Alliances</a></li></ul>',21)])])}const p=a(r,[["render",i]]);export{u as __pageData,p as default};
